class Solution:
    def minimizeXor(self, num1: int, num2: int) -> int:
        k = num2.bit_count()
        n = num1.bit_length()
        x = 0
        for i in range(n - 1, -1, -1):
            if k == 0:
                break
            if num1 & (1 << i):
                x |= 1 << i
                k -= 1
        for i in range(0, n):
            if k == 0:
                break
            if not (x & (1 << i)):
                x |= 1 << i
                k -= 1
        return x
